// src/pages/ExpensesPage.js
import React, { useState, useEffect } from "react";
import { useApp } from "../context/AppContext";
import { expenseAPI } from "../utils/api";
import ExpenseModal from "../components/modals/ExpenseModal";
import DeleteModal from "../components/modals/DeleteModal";
import toast from "react-hot-toast";
import { formatDate } from "../utils/khmerUtils";

const CATEGORIES = [
  "food",
  "drink",
  "fruit",
  "transport",
  "clothing",
  "health",
  "entertainment",
  "education",
  "utilities",
  "shopping",
  "other",
];

export default function ExpensesPage() {
  const { t, formatAmount, formatNum, language } = useApp();

  const [expenses, setExpenses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addModal, setAddModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [deleteId, setDeleteId] = useState(null);
  const [deleting, setDeleting] = useState(false);
  const [filterCat, setFilterCat] = useState("");
  const [search, setSearch] = useState("");

  // ✅ NEW: View mode state
  const [viewMode, setViewMode] = useState("table"); // table | grid

  const loadExpenses = async () => {
    setLoading(true);
    try {
      const params = {};
      if (filterCat) params.category = filterCat;
      const res = await expenseAPI.getAll(params);
      setExpenses(res.data || []);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadExpenses();
  }, [filterCat]);

  const handleDelete = async () => {
    setDeleting(true);
    try {
      await expenseAPI.delete(deleteId);
      toast.success(t("deletedSuccess"));
      setDeleteId(null);
      loadExpenses();
    } catch (err) {
      toast.error(err.message);
    } finally {
      setDeleting(false);
    }
  };

  const filtered = expenses.filter(
    (e) => !search || e.itemName?.toLowerCase().includes(search.toLowerCase()),
  );

  const totalUSD = filtered.reduce((s, e) => s + (e.amountUSD || 0), 0);

  return (
    <div className="space-y-6 animate-fade-in">
      {/* ===== Header ===== */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1
            className="text-2xl font-bold"
            style={{ color: "var(--text-primary)" }}
          >
            💸 {t("expenses")}
          </h1>
          <p
            className="text-sm mt-1"
            style={{ color: "var(--text-secondary)" }}
          >
            {t("total")}:{" "}
            <span className="font-semibold text-primary-500">
              {formatAmount(totalUSD)}
            </span>{" "}
            · {formatNum(filtered.length)} {t("items")}
          </p>
        </div>

        <button
          className="btn btn-primary"
          onClick={() => {
            setEditData(null);
            setAddModal(true);
          }}
        >
          + {t("addNew")}
        </button>
      </div>

      {/* ===== Filters ===== */}
      <div className="card p-4">
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
          <input
            type="text"
            placeholder={t("search")}
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="form-input"
          />

          <select
            value={filterCat}
            onChange={(e) => setFilterCat(e.target.value)}
            className="form-input"
          >
            <option value="">{t("allCategories")}</option>
            {CATEGORIES.map((c) => (
              <option key={c} value={c}>
                {t(c)}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* ===== View Toggle ===== */}
      <div className="flex justify-end">
        <div className="inline-flex bg-[var(--bg-primary)] border border-[var(--border)] rounded-lg p-1">
          <button
            onClick={() => setViewMode("table")}
            className={`px-3 py-1.5 text-sm rounded-md transition ${
              viewMode === "table"
                ? "bg-primary-500 text-white"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-primary)]"
            }`}
          >
            📋 Table
          </button>

          <button
            onClick={() => setViewMode("grid")}
            className={`px-3 py-1.5 text-sm rounded-md transition ${
              viewMode === "grid"
                ? "bg-primary-500 text-white"
                : "text-[var(--text-secondary)] hover:bg-[var(--bg-primary)]"
            }`}
          >
            🧾 Grid
          </button>
        </div>
      </div>

      {/* ===== Content ===== */}
      <div className="card overflow-hidden">
        {loading ? (
          <div className="p-10 text-center text-sm text-[var(--text-secondary)]">
            {t("loading")}
          </div>
        ) : filtered.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-5xl mb-4">🧾</div>
            <div className="font-semibold text-[var(--text-secondary)]">
              {t("noExpenses")}
            </div>
          </div>
        ) : (
          <>
            {/* ================= TABLE VIEW ================= */}
            {viewMode === "table" && (
              <div className="hidden md:block overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="bg-[var(--bg-primary)] border-b border-[var(--border)]">
                      <th className="px-4 py-3 text-left text-xs uppercase text-[var(--text-secondary)]">
                        {t("itemName")}
                      </th>
                      <th className="px-4 py-3 text-left text-xs uppercase text-[var(--text-secondary)]">
                        {t("category")}
                      </th>
                      <th className="px-4 py-3 text-left text-xs uppercase text-[var(--text-secondary)]">
                        {t("amount")}
                      </th>
                      <th className="px-4 py-3 text-left text-xs uppercase text-[var(--text-secondary)]">
                        {t("date")}
                      </th>
                      <th className="px-4 py-3 text-right text-xs uppercase text-[var(--text-secondary)]">
                        {t("actions")}
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.map((e) => (
                      <tr
                        key={e._id}
                        className="border-b border-[var(--border)] hover:bg-[var(--bg-primary)] transition"
                      >
                        <td className="px-4 py-3 font-medium">{e.itemName}</td>
                        <td className="px-4 py-3">
                          <span className="badge badge-planned">
                            {t(e.category)}
                          </span>
                        </td>
                        <td className="px-4 py-3 font-bold text-primary-500">
                          {formatAmount(e.amountUSD, e.amountKHR)}
                        </td>
                        <td className="px-4 py-3 text-[var(--text-secondary)]">
                          {formatDate(e.date, language, "medium")}
                        </td>
                        <td className="px-4 py-3 text-right">
                          <button
                            className="btn btn-ghost p-2"
                            onClick={() => {
                              setEditData(e);
                              setAddModal(true);
                            }}
                          >
                            ✏️
                          </button>
                          <button
                            className="btn btn-ghost p-2"
                            onClick={() => setDeleteId(e._id)}
                          >
                            🗑️
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            {/* ================= GRID VIEW ================= */}
            {viewMode === "grid" && (
              <div className="hidden md:grid md:grid-cols-2 lg:grid-cols-3 gap-4 p-4">
                {filtered.map((e) => (
                  <div
                    key={e._id}
                    className="bg-[var(--bg-primary)] border border-[var(--border)] 
                               rounded-xl p-4 shadow-sm hover:shadow-md 
                               transition-all duration-200"
                  >
                    <div className="flex justify-between items-start">
                      <div className="flex items-center gap-3">
                        <div className="text-2xl">{e.categoryEmoji}</div>
                        <div>
                          <div className="font-semibold truncate">
                            {e.itemName}
                          </div>
                          <div className="text-xs text-[var(--text-secondary)]">
                            {formatDate(e.date, language, "medium")}
                          </div>
                        </div>
                      </div>

                      <div className="flex gap-1">
                        <button
                          className="btn btn-ghost p-2"
                          onClick={() => {
                            setEditData(e);
                            setAddModal(true);
                          }}
                        >
                          ✏️
                        </button>
                        <button
                          className="btn btn-ghost p-2"
                          onClick={() => setDeleteId(e._id)}
                        >
                          🗑️
                        </button>
                      </div>
                    </div>

                    <div className="mt-4 flex justify-between items-center">
                      <span className="badge badge-planned">
                        {t(e.category)}
                      </span>

                      <div className="text-primary-500 font-bold text-lg">
                        {formatAmount(e.amountUSD, e.amountKHR)}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* ================= MOBILE CARDS (UNCHANGED) ================= */}
            <div className="md:hidden divide-y divide-[var(--border)]">
              {filtered.map((e) => (
                <div key={e._id} className="p-4 flex gap-3">
                  <div className="text-2xl">{e.categoryEmoji}</div>

                  <div className="flex-1 min-w-0">
                    <div className="font-semibold truncate">{e.itemName}</div>
                    <div className="text-xs text-[var(--text-secondary)]">
                      {formatDate(e.date, language, "medium")}
                    </div>
                    <div className="text-primary-500 font-bold mt-1">
                      {formatAmount(e.amountUSD, e.amountKHR)}
                    </div>
                  </div>

                  <div className="flex flex-col gap-1">
                    <button
                      className="btn btn-ghost p-2"
                      onClick={() => {
                        setEditData(e);
                        setAddModal(true);
                      }}
                    >
                      ✏️
                    </button>
                    <button
                      className="btn btn-ghost p-2"
                      onClick={() => setDeleteId(e._id)}
                    >
                      🗑️
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}
      </div>

      <ExpenseModal
        isOpen={addModal}
        onClose={() => {
          setAddModal(false);
          setEditData(null);
        }}
        editData={editData}
        onSuccess={loadExpenses}
      />

      <DeleteModal
        isOpen={!!deleteId}
        onClose={() => setDeleteId(null)}
        onConfirm={handleDelete}
        loading={deleting}
      />
    </div>
  );
}
